/**
 * Flavor Form Validation - Minified
 * Cumple con WCAG 3.3.1 (Error Identification)
 * @package Flavor_Chat_IA
 * @since 1.0.0
 */
(function(){'use strict';let errorIdCounter=0;window.FlavorValidation={config:{errorClass:'flavor-input--error',successClass:'flavor-input--success',errorMessageClass:'flavor-field-error',validateAttribute:'data-validate',formAttribute:'data-flavor-validate',debounceDelay:300,errorIdPrefix:'flavor-error'},messages:{required:'Este campo es requerido',email:'Por favor, introduce un email valido',min:'Debe tener al menos {param} caracteres',max:'No puede exceder {param} caracteres',numeric:'Solo se permiten numeros',url:'Por favor, introduce una URL valida',phone:'Por favor, introduce un telefono valido',date:'Por favor, introduce una fecha valida',match:'Los campos no coinciden',pattern:'El formato no es valido',minValue:'El valor minimo es {param}',maxValue:'El valor maximo es {param}',integer:'Debe ser un numero entero',alphanumeric:'Solo se permiten letras y numeros',noSpaces:'No se permiten espacios',fileSize:'El archivo excede el tamano maximo de {param}MB',fileType:'Tipo de archivo no permitido'},init:function(customConfig){if(customConfig){this.config=Object.assign({},this.config,customConfig)}this.setupForms();this.setupRealTimeValidation();this.setupCustomValidators()},setupForms:function(){const validationForms=document.querySelectorAll('form['+this.config.formAttribute+']');validationForms.forEach(form=>{form.addEventListener('submit',this.handleSubmit.bind(this));form.setAttribute('novalidate','true')})},setupRealTimeValidation:function(){const validateFields=document.querySelectorAll('['+this.config.validateAttribute+']');validateFields.forEach(input=>{input.addEventListener('blur',()=>this.validateField(input));let debounceTimer;input.addEventListener('input',()=>{clearTimeout(debounceTimer);debounceTimer=setTimeout(()=>{if(input.classList.contains(this.config.errorClass)){this.validateField(input)}else{this.clearError(input)}},this.config.debounceDelay)});if(input.type==='checkbox'||input.type==='radio'||input.tagName==='SELECT'){input.addEventListener('change',()=>this.validateField(input))}})},setupCustomValidators:function(){this.customValidators={}},registerValidator:function(validatorName,validatorFunction,validatorMessage){this.customValidators[validatorName]={validate:validatorFunction,message:validatorMessage}},validateField:function(field){const validationRules=field.getAttribute(this.config.validateAttribute);if(!validationRules)return true;const rules=validationRules.split('|');const fieldValue=this.getFieldValue(field);for(const rule of rules){const validationError=this.checkRule(rule,fieldValue,field);if(validationError){this.showError(field,validationError);return false}}this.showSuccess(field);return true},getFieldValue:function(field){if(field.type==='checkbox'){return field.checked}if(field.type==='radio'){const radioGroup=document.querySelectorAll('input[name="'+field.name+'"]');for(const radio of radioGroup){if(radio.checked)return radio.value}return''}if(field.type==='file'){return field.files}if(field.tagName==='SELECT'&&field.multiple){return Array.from(field.selectedOptions).map(opt=>opt.value)}return field.value.trim()},checkRule:function(rule,value,field){const[ruleName,ruleParam]=rule.split(':');switch(ruleName){case'required':if(field.type==='checkbox'&&!value){return this.messages.required}if(field.type==='file'&&(!value||value.length===0)){return this.messages.required}if(Array.isArray(value)&&value.length===0){return this.messages.required}if(typeof value==='string'&&!value){return this.messages.required}break;case'email':if(value&&!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)){return this.messages.email}break;case'min':if(value&&value.length<parseInt(ruleParam,10)){return this.messages.min.replace('{param}',ruleParam)}break;case'max':if(value&&value.length>parseInt(ruleParam,10)){return this.messages.max.replace('{param}',ruleParam)}break;case'numeric':if(value&&!/^\d+$/.test(value)){return this.messages.numeric}break;case'integer':if(value&&!/^-?\d+$/.test(value)){return this.messages.integer}break;case'url':if(value&&!/^https?:\/\/[^\s]+$/.test(value)){return this.messages.url}break;case'phone':if(value&&!/^[\d\s\-\+\(\)]{9,20}$/.test(value)){return this.messages.phone}break;case'date':if(value&&isNaN(Date.parse(value))){return this.messages.date}break;case'match':const matchField=document.querySelector('[name="'+ruleParam+'"]');if(matchField&&value!==matchField.value){return this.messages.match}break;case'pattern':try{const patternRegex=new RegExp(ruleParam);if(value&&!patternRegex.test(value)){return this.messages.pattern}}catch(patternError){console.error('FlavorValidation: Patron invalido',ruleParam)}break;case'minValue':if(value&&parseFloat(value)<parseFloat(ruleParam)){return this.messages.minValue.replace('{param}',ruleParam)}break;case'maxValue':if(value&&parseFloat(value)>parseFloat(ruleParam)){return this.messages.maxValue.replace('{param}',ruleParam)}break;case'alphanumeric':if(value&&!/^[a-zA-Z0-9]+$/.test(value)){return this.messages.alphanumeric}break;case'noSpaces':if(value&&/\s/.test(value)){return this.messages.noSpaces}break;case'fileSize':if(value&&value.length>0){const maxSizeBytes=parseFloat(ruleParam)*1024*1024;for(const file of value){if(file.size>maxSizeBytes){return this.messages.fileSize.replace('{param}',ruleParam)}}}break;case'fileType':if(value&&value.length>0){const allowedTypes=ruleParam.split(',');for(const file of value){const fileExtension=file.name.split('.').pop().toLowerCase();if(!allowedTypes.includes(fileExtension)){return this.messages.fileType}}}break;default:if(this.customValidators[ruleName]){const customValidator=this.customValidators[ruleName];if(!customValidator.validate(value,ruleParam,field)){return customValidator.message.replace('{param}',ruleParam)}}break}return null},generateErrorId:function(field){errorIdCounter++;const fieldIdentifier=field.id||field.name||'';const sanitizedIdentifier=fieldIdentifier.replace(/[^a-zA-Z0-9-_]/g,'-');return this.config.errorIdPrefix+'-'+sanitizedIdentifier+'-'+errorIdCounter},getExistingAriaDescribedBy:function(field){const currentDescribedBy=field.getAttribute('data-original-describedby');return currentDescribedBy||''},saveOriginalAriaDescribedBy:function(field){if(!field.hasAttribute('data-original-describedby')){const existingDescribedBy=field.getAttribute('aria-describedby')||'';field.setAttribute('data-original-describedby',existingDescribedBy)}},showError:function(field,errorMessage){this.saveOriginalAriaDescribedBy(field);this.clearError(field);field.classList.add(this.config.errorClass);field.classList.remove(this.config.successClass);field.setAttribute('aria-invalid','true');const errorElement=document.createElement('span');errorElement.className=this.config.errorMessageClass;errorElement.setAttribute('role','alert');errorElement.setAttribute('aria-live','assertive');errorElement.setAttribute('aria-atomic','true');errorElement.textContent=errorMessage;const errorId=this.generateErrorId(field);errorElement.id=errorId;const existingDescribedBy=this.getExistingAriaDescribedBy(field);const newDescribedBy=existingDescribedBy?existingDescribedBy+' '+errorId:errorId;field.setAttribute('aria-describedby',newDescribedBy);const fieldContainer=field.closest('.flavor-field')||field.parentNode;fieldContainer.appendChild(errorElement);field.dispatchEvent(new CustomEvent('flavor:validation:error',{detail:{message:errorMessage,field:field,errorId:errorId},bubbles:true}))},showSuccess:function(field){this.clearError(field);field.classList.add(this.config.successClass);field.classList.remove(this.config.errorClass);field.setAttribute('aria-invalid','false');field.dispatchEvent(new CustomEvent('flavor:validation:success',{detail:{field:field},bubbles:true}))},clearError:function(field){field.classList.remove(this.config.errorClass,this.config.successClass);field.removeAttribute('aria-invalid');const originalDescribedBy=field.getAttribute('data-original-describedby');if(originalDescribedBy){field.setAttribute('aria-describedby',originalDescribedBy)}else{field.removeAttribute('aria-describedby')}const fieldContainer=field.closest('.flavor-field')||field.parentNode;const existingError=fieldContainer.querySelector('.'+this.config.errorMessageClass);if(existingError){existingError.remove()}},handleSubmit:function(submitEvent){const form=submitEvent.target;let isFormValid=true;const validationErrors=[];const formFields=form.querySelectorAll('['+this.config.validateAttribute+']');formFields.forEach(field=>{if(!this.validateField(field)){isFormValid=false;validationErrors.push({field:field,name:field.name||field.id})}});if(!isFormValid){submitEvent.preventDefault();const firstErrorField=form.querySelector('.'+this.config.errorClass);if(firstErrorField){firstErrorField.focus();firstErrorField.scrollIntoView({behavior:'smooth',block:'center'})}form.dispatchEvent(new CustomEvent('flavor:validation:invalid',{detail:{errors:validationErrors},bubbles:true}))}else{form.dispatchEvent(new CustomEvent('flavor:validation:valid',{detail:{form:form},bubbles:true}))}},validateForm:function(form){if(typeof form==='string'){form=document.querySelector(form)}if(!form)return false;let isFormValid=true;const formFields=form.querySelectorAll('['+this.config.validateAttribute+']');formFields.forEach(field=>{if(!this.validateField(field)){isFormValid=false}});return isFormValid},resetValidation:function(form){if(typeof form==='string'){form=document.querySelector(form)}if(!form)return;const formFields=form.querySelectorAll('['+this.config.validateAttribute+']');formFields.forEach(field=>{this.clearError(field)})},setMessages:function(customMessages){this.messages=Object.assign({},this.messages,customMessages)},getFieldState:function(field){return{isValid:!field.classList.contains(this.config.errorClass),hasSuccess:field.classList.contains(this.config.successClass),hasError:field.classList.contains(this.config.errorClass)}}};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',function(){FlavorValidation.init()})}else{FlavorValidation.init()}})();
